// Broadcast fan-out — OTP `[Pid ! Msg || Pid <- pg:get_members(group)]`. Kept in
// lib (auto-generated); the user touches on_enter/handle_* only.

inline void VucmCampaign::broadcast_progress_progress(const CampaignProgress& msg) {
    // Monitor the group (OTP pg:monitor — idempotent), then cast to EACH watched
    // member. group identity = msg_type_name<CampaignProgress>(); members pg_join the
    // same type → register_cast<CampaignProgress> delivers to their handle_cast. The impl
    // may pg_members<CampaignProgress>() to skip work when empty.
    pg_watch<CampaignProgress>();
    uint8_t _buf[8192];
    pb_ostream_t _os = pb_ostream_from_buffer(_buf, sizeof(_buf));
    if (!pb_encode(&_os, ::theia::runtime::RemoteCodec<CampaignProgress>::fields(), &msg))
        return;
    pg_.broadcast_members<CampaignProgress>(_buf, static_cast<uint16_t>(_os.bytes_written));
}




